1	// claim-office.ts
2	
3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_SURCHARGE = 0.1;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	};
13	
14	type Item = { type: string };
15	type Step = { op: string; items: Item[] };
16	type Scenario = { steps: Step[] };
17	
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	const BLOCK_SIZE = 3;
20	const BLOCK_BASE_PREMIUM = 60;
21	
22	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
23	
24	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
25	
26	const countByType = (items: Item[]): Map<string, number> => {
27	  const counts = new Map<string, number>();
28	  for (const item of items) {
29	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
30	  }
31	  return counts;
32	};
33	
34	const componentGroupPremium = (type: string, count: number): number =>
35	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
36	
37	const sumItemBasePremiums = (items: Item[]): number => {
38	  const nonComponents = items.filter((item) => !isComponent(item));
39	  const components = items.filter(isComponent);
40	  const nonComponentsTotal = nonComponents.reduce(
41	    (sum, item) => sum + itemBasePremium(item),
42	    0,
43	  );
44	  const componentsTotal = Array.from(countByType(components)).reduce(
45	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
46	    0,
47	  );
48	  return nonComponentsTotal + componentsTotal;
49	};
50	
51	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
52	  const step = (scenario as Scenario).steps[0];
53	  const itemsBase = sumItemBasePremiums(step.items);
54	  const policyBase = itemsBase + itemsBase * FIRST_INSURANCE_SURCHARGE;
55	  const premium = Math.ceil(policyBase + PROCESSING_FEE);
56	  return { results: [{ premium }] };
57	}
